import React, { useEffect, useMemo, useState } from 'react';
import { emailService } from '../services/api';
import '../styles/Dashboard.css';

const StatCard = ({ title, value, type, icon }) => {
  return (
    <div className={`stat-card ${type || ''}`}>
      <div className="stat-card-header">
        <span className="stat-card-icon">{icon}</span>
        <h3>{title}</h3>
      </div>
      <div className="stat-card-value">{value}</div>
    </div>
  );
};

const CURRENT_MODEL_HINTS = {
  url: ['random forest', 'random forest (original - 300 trees)'],
  content: ['logistic regression', 'logistic regression (saga)'],
};

const formatMetric = (value) => {
  if (value === null || value === undefined || Number.isNaN(Number(value))) {
    return '—';
  }
  return `${(Number(value) * 100).toFixed(2)}%`;
};

const formatSeconds = (value) => {
  if (value === null || value === undefined || Number.isNaN(Number(value))) {
    return '—';
  }
  return `${Number(value).toFixed(2)}s`;
};

const safeArray = (value) => (Array.isArray(value) ? value : []);

const normalizeModelMetrics = (list) =>
  safeArray(list)
    .filter((item) => item && item.status !== 'failed')
    .map((item) => ({
      model_name: item.model_name || 'Unknown Model',
      accuracy: Number(item.accuracy || 0),
      precision: Number(item.precision || 0),
      recall: Number(item.recall || 0),
      f1: Number(item.f1 || 0),
      roc_auc: Number(item.roc_auc || 0),
      training_time_seconds: Number(item.training_time_seconds || 0),
      status: item.status || 'success',
    }));

const matchesCurrentModel = (modelName, family) => {
  const normalized = String(modelName || '').toLowerCase();
  return (CURRENT_MODEL_HINTS[family] || []).some((hint) => normalized.includes(hint));
};

const findCurrentModelInComparison = (models, family) => {
  return models.find((model) => matchesCurrentModel(model.model_name, family)) || null;
};

const buildFallbackCurrentModel = (family, metrics) => {
  const names = {
    url: 'Random Forest',
    content: 'Logistic Regression',
  };

  return {
    model_name: names[family],
    accuracy: Number(metrics?.accuracy || 0),
    precision: Number(metrics?.precision || 0),
    recall: Number(metrics?.recall || 0),
    f1: Number(metrics?.f1 || 0),
    roc_auc: Number(metrics?.roc_auc || 0),
    training_time_seconds: Number(metrics?.training_time_seconds || 0),
    status: 'success',
    isFallback: true,
  };
};

const getBestAlternative = (models, currentModelName) => {
  const alternatives = safeArray(models).filter(
    (model) => model.model_name !== currentModelName
  );

  if (!alternatives.length) {
    return null;
  }

  return [...alternatives].sort((a, b) => b.f1 - a.f1)[0];
};

const ComparisonTable = ({ title, currentModel, models }) => {
  const bestAlternative = useMemo(
    () => getBestAlternative(models, currentModel?.model_name),
    [models, currentModel]
  );

  return (
    <div className="phase2-model-group" style={{ marginTop: '1.5rem' }}>
      <div style={{ marginBottom: '0.75rem' }}>
        <h3>{title}</h3>
        {currentModel && (
          <p style={{ margin: 0, opacity: 0.85 }}>
            Current production model: <strong>{currentModel.model_name}</strong>
          </p>
        )}
      </div>

      {currentModel && (
        <div
          style={{
            border: '1px solid rgba(255,255,255,0.12)',
            borderRadius: '12px',
            padding: '1rem',
            marginBottom: '1rem',
          }}
        >
          <h4 style={{ marginTop: 0 }}>Currently used model</h4>
          <div className="phase2-current-model-grid" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(140px, 1fr))', gap: '0.75rem' }}>
            <div><strong>Accuracy</strong><br />{formatMetric(currentModel.accuracy)}</div>
            <div><strong>Precision</strong><br />{formatMetric(currentModel.precision)}</div>
            <div><strong>Recall</strong><br />{formatMetric(currentModel.recall)}</div>
            <div><strong>F1</strong><br />{formatMetric(currentModel.f1)}</div>
            <div><strong>ROC AUC</strong><br />{formatMetric(currentModel.roc_auc)}</div>
            <div><strong>Training Time</strong><br />{formatSeconds(currentModel.training_time_seconds)}</div>
          </div>
        </div>
      )}

      {bestAlternative && currentModel && (
        <div
          style={{
            border: '1px solid rgba(255,255,255,0.12)',
            borderRadius: '12px',
            padding: '1rem',
            marginBottom: '1rem',
          }}
        >
          <h4 style={{ marginTop: 0 }}>Best alternative not currently used</h4>
          <p style={{ marginTop: 0 }}>
            <strong>{bestAlternative.model_name}</strong>
          </p>
          <p style={{ marginBottom: '0.5rem' }}>
            F1: {formatMetric(bestAlternative.f1)} vs current {formatMetric(currentModel.f1)}
          </p>
          <p style={{ marginBottom: '0.5rem' }}>
            Accuracy: {formatMetric(bestAlternative.accuracy)} vs current {formatMetric(currentModel.accuracy)}
          </p>
          <p style={{ marginBottom: 0 }}>
            ROC AUC: {formatMetric(bestAlternative.roc_auc)} vs current {formatMetric(currentModel.roc_auc)}
          </p>
        </div>
      )}

      <div style={{ overflowX: 'auto' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr>
              <th style={{ textAlign: 'left', padding: '0.75rem' }}>Model</th>
              <th style={{ textAlign: 'left', padding: '0.75rem' }}>Used Now</th>
              <th style={{ textAlign: 'left', padding: '0.75rem' }}>Accuracy</th>
              <th style={{ textAlign: 'left', padding: '0.75rem' }}>Precision</th>
              <th style={{ textAlign: 'left', padding: '0.75rem' }}>Recall</th>
              <th style={{ textAlign: 'left', padding: '0.75rem' }}>F1</th>
              <th style={{ textAlign: 'left', padding: '0.75rem' }}>ROC AUC</th>
              <th style={{ textAlign: 'left', padding: '0.75rem' }}>Train Time</th>
            </tr>
          </thead>
          <tbody>
            {models.map((model) => {
              const isCurrent = currentModel?.model_name === model.model_name;

              return (
                <tr
                  key={`${title}-${model.model_name}`}
                  style={{
                    borderTop: '1px solid rgba(255,255,255,0.08)',
                    background: isCurrent ? 'rgba(37, 99, 235, 0.12)' : 'transparent',
                  }}
                >
                  <td style={{ padding: '0.75rem' }}>{model.model_name}</td>
                  <td style={{ padding: '0.75rem' }}>{isCurrent ? 'Yes' : 'No'}</td>
                  <td style={{ padding: '0.75rem' }}>{formatMetric(model.accuracy)}</td>
                  <td style={{ padding: '0.75rem' }}>{formatMetric(model.precision)}</td>
                  <td style={{ padding: '0.75rem' }}>{formatMetric(model.recall)}</td>
                  <td style={{ padding: '0.75rem' }}>{formatMetric(model.f1)}</td>
                  <td style={{ padding: '0.75rem' }}>{formatMetric(model.roc_auc)}</td>
                  <td style={{ padding: '0.75rem' }}>{formatSeconds(model.training_time_seconds)}</td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
};

const Dashboard = () => {
  const [stats, setStats] = useState({
    total_emails: 0,
    phishing_detected: 0,
    safe_emails: 0,
    average_risk_score: 0,
    phishing_percentage: 0,
    threat_distribution: {},
    phase2_metrics: {},
  });

  const [phase2Comparison, setPhase2Comparison] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetchStatistics = async () => {
    try {
      setLoading(true);

      const [statistics, comparison] = await Promise.all([
        emailService.getStatistics(),
        emailService.getPhase2ModelComparison(),
      ]);

      setStats(statistics);
      setPhase2Comparison(comparison);
      setError(null);
    } catch (err) {
      setError('Failed to load dashboard');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchStatistics();
    const interval = setInterval(fetchStatistics, 30000);
    return () => clearInterval(interval);
  }, []);

  const urlMetadataMetrics = stats?.phase2_metrics?.url_metrics || phase2Comparison?.url_metrics || {};
  const contentMetadataMetrics = stats?.phase2_metrics?.content_metrics || phase2Comparison?.content_metrics || {};

  const urlComparisonModels = normalizeModelMetrics(
    phase2Comparison?.comparison?.report?.url_models?.metrics || []
  );

  const contentComparisonModels = normalizeModelMetrics(
    phase2Comparison?.comparison?.report?.content_models?.metrics || []
  );

  const currentUrlModel =
    findCurrentModelInComparison(urlComparisonModels, 'url') ||
    buildFallbackCurrentModel('url', urlMetadataMetrics);

  const currentContentModel =
    findCurrentModelInComparison(contentComparisonModels, 'content') ||
    buildFallbackCurrentModel('content', contentMetadataMetrics);

  const sortedUrlModels = useMemo(() => {
    const models = [...urlComparisonModels];
    if (!models.length && currentUrlModel) {
      return [currentUrlModel];
    }
    return models.sort((a, b) => b.f1 - a.f1);
  }, [urlComparisonModels, currentUrlModel]);

  const sortedContentModels = useMemo(() => {
    const models = [...contentComparisonModels];
    if (!models.length && currentContentModel) {
      return [currentContentModel];
    }
    return models.sort((a, b) => b.f1 - a.f1);
  }, [contentComparisonModels, currentContentModel]);

  if (loading && !stats.total_emails) {
    return <div className="dashboard-loading">Loading dashboard...</div>;
  }

  return (
    <div className="dashboard-container">
      <div className="dashboard-header">
        <h1>Security Dashboard</h1>
        <p>Operational phishing detection overview with live model-performance context.</p>
      </div>

      <div
        className="stats-grid"
        style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: '1rem' }}
      >
        <StatCard title="Total Emails" value={stats.total_emails} type="primary" icon="📧" />
        <StatCard title="Phishing Detected" value={stats.phishing_detected} type="danger" icon="🚨" />
        <StatCard title="Safe Emails" value={stats.safe_emails} type="success" icon="✅" />
        <StatCard title="Average Risk" value={(stats.average_risk_score || 0).toFixed(3)} type="warning" icon="📈" />
      </div>

      <div
        style={{
          marginTop: '1.5rem',
          border: '1px solid rgba(255,255,255,0.12)',
          borderRadius: '12px',
          padding: '1rem',
        }}
      >
        <h2>Threat Detection Rate</h2>
        <p style={{ fontSize: '1.25rem', margin: 0 }}>
          <strong>{stats.phishing_percentage}%</strong> of emails identified as phishing
        </p>
      </div>

      <div
        style={{
          marginTop: '1.5rem',
          border: '1px solid rgba(255,255,255,0.12)',
          borderRadius: '12px',
          padding: '1rem',
        }}
      >
        <h2>Threat Types Distribution</h2>
        {Object.keys(stats.threat_distribution || {}).length > 0 ? (
          <ul style={{ marginBottom: 0 }}>
            {Object.entries(stats.threat_distribution).map(([threat, count]) => (
              <li key={threat}>
                {threat}: <strong>{count}</strong>
              </li>
            ))}
          </ul>
        ) : (
          <p style={{ marginBottom: 0 }}>No threats detected yet.</p>
        )}
      </div>

      <div
        style={{
          marginTop: '1.5rem',
          border: '1px solid rgba(255,255,255,0.12)',
          borderRadius: '12px',
          padding: '1rem',
        }}
      >
        <h2>Phase 2 Model Performance</h2>
        <p>
          This section now shows the actual models used in production and compares their metrics
          against alternative models from the Phase 2 comparison report.
        </p>

        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))',
            gap: '1rem',
            marginTop: '1rem',
          }}
        >
          <div
            style={{
              border: '1px solid rgba(255,255,255,0.10)',
              borderRadius: '10px',
              padding: '1rem',
            }}
          >
            <h3 style={{ marginTop: 0 }}>Current URL model</h3>
            <p style={{ marginBottom: 0.5 }}>Random Forest</p>
            <small>Artifact: backend/artifacts/phase2/url_model.joblib</small>
          </div>

          <div
            style={{
              border: '1px solid rgba(255,255,255,0.10)',
              borderRadius: '10px',
              padding: '1rem',
            }}
          >
            <h3 style={{ marginTop: 0 }}>Current content model</h3>
            <p style={{ marginBottom: 0.5 }}>Logistic Regression</p>
            <small>Artifact: backend/artifacts/phase2/content_model.joblib</small>
          </div>
        </div>

        <ComparisonTable
          title="URL model comparison"
          currentModel={currentUrlModel}
          models={sortedUrlModels}
        />

        <ComparisonTable
          title="Content model comparison"
          currentModel={currentContentModel}
          models={sortedContentModels}
        />

        <div style={{ marginTop: '1.5rem' }}>
          <h3>Training sources</h3>
          <ul style={{ marginBottom: 0 }}>
            {(stats.phase2_metrics?.data_sources || []).map((source) => (
              <li key={`${source.name}-${source.source}`}>
                <strong>{source.name}</strong> — {source.purpose}
              </li>
            ))}
          </ul>
        </div>

        {phase2Comparison?.comparison?.available === false && (
          <div
            style={{
              marginTop: '1rem',
              border: '1px solid rgba(234, 179, 8, 0.35)',
              borderRadius: '10px',
              padding: '1rem',
            }}
          >
            <strong>Comparison report not found.</strong>
            <p style={{ marginBottom: 0 }}>
              Run <code>python backend/train_phase2_model_comparison.py</code> to generate
              <code> backend/artifacts/model_comparison/model_comparison_report.json</code>.
            </p>
          </div>
        )}
      </div>

      {error && (
        <div
          style={{
            marginTop: '1rem',
            border: '1px solid rgba(220, 38, 38, 0.35)',
            borderRadius: '10px',
            padding: '1rem',
          }}
        >
          {error}
        </div>
      )}
    </div>
  );
};

export default Dashboard;
